arguments.command:
cd /tmp/sv-063c13da48dd45d584763c212ec224ac/symbols && \
# Extract dynamic symbols sorted by address and find nearest for each PC
# Addresses: 0x222098, 0x222234, 0x19bac0, 0x19bc14
readelf --dyn-syms libmonosgen-2.0.so 2>/dev/null | awk '$4 == "FUNC" && $2 != "0000000000000000" {print $2, $3, $8}' | sort > mono_syms.txt && \
wc -l mono_syms.txt && \
# Find function containing each address
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  dec_addr=$((addr))
  match=$(awk -v target="$dec_addr" '{
    addr = strtonum("0x"$1); size = strtonum($2);
    if (target >= addr && target < addr + size) print $3, "+" sprintf("0x%x", target - addr)
  }' mono_syms.txt)
  if [ -z "$match" ]; then
    # Find nearest lower symbol
    match=$(awk -v target="$dec_addr" '{
      addr = strtonum("0x"$1)
      if (addr <= target) { name=$3; sym_addr=addr }
    } END { if (name) print name, "+" sprintf("0x%x", target - sym_addr) }' mono_syms.txt)
  fi
  printf "  %s -> %s\n" "$addr" "$match"
done

