arguments.command:
cd /tmp/sv-063c13da48dd45d584763c212ec224ac/symbols && \
# Check if these addresses fall within the function size bounds
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  dec_addr=$((addr))
  echo "=== $addr ==="
  # Show the closest symbols with their sizes
  awk -v target="$dec_addr" '{
    addr = strtonum("0x"$1); size = strtonum($2);
    if (addr <= target && target < addr + size) print "MATCH:", $3, "size="$2, "offset=" sprintf("0x%x", target - addr)
    else if (addr <= target && target - addr < 0x100) print "NEAR:", $3, "size="$2, "gap=" sprintf("0x%x", target - addr)
  }' mono_syms_full.txt
  # Also show nearest below regardless
  awk -v target="$dec_addr" '{
    addr = strtonum("0x"$1); size = strtonum($2)
    if (addr <= target) { name=$3; sym_addr=addr; sym_size=size }
  } END { print "NEAREST:", name, "at", sprintf("0x%x", sym_addr), "size=" sym_size, "offset=" sprintf("0x%x", target - sym_addr) }' mono_syms_full.txt
done

